// Input-Validierung und Extraktion
const body = $input.first().json.body;

if (
  !body.studentPrompt ||
  !body.categoryId ||
  !body.topic ||
  !body.difficulty ||
  !body.language ||
  !body.outputFormat
) {
  throw new Error(
    'Fehlende Parameter: studentPrompt, categoryId, topic, difficulty, language und outputFormat sind erforderlich'
  );
}

const {
  studentPrompt,
  categoryId,
  categoryName,
  topic,
  difficulty,
  language,
  outputFormat
} = body;

// System-Prompt für KI
const systemPrompt = `
Du bist eine erfahrene Lehrkraft für die gymnasiale Oberstufe.
Deine Aufgabe ist es, anspruchsvolle, didaktisch saubere und realistische Lernaufgaben zu erstellen.

WICHTIG:
- Erstelle NUR die AUFGABENSTELLUNG
- KEINE Lösungen
- KEINE Rechenwege
- KEINE Hinweise zur Lösung
- KEINE Musterlösungen oder Antworten

ANTWORTE NUR MIT EINEM VALIDEN JSON-OBJEKT, OHNE ZUSÄTZLICHEN TEXT!
`.trim();

// User-Prompt für KI
const userPrompt = `
Erstelle eine umfangreiche Lernaufgabe für die gymnasiale Oberstufe mit folgenden Parametern:

- Themenbereich: ${categoryName || 'Allgemein'}
- Thema: ${topic}
- Schwierigkeit: ${difficulty}
- Sprache: ${language}
- Ausgabeformat: Markdown

Studenten-Prompt:
"${studentPrompt}"

Die Aufgabe soll:
- anspruchsvoll sein (Oberstufen-Niveau)
- mehrere Teilaufgaben enthalten (z. B. a), b), c))
- zum selbstständigen Denken anregen
- KEINE Lösung, KEINE Tipps, KEINE Rechenschritte enthalten

Die Antwort MUSS exakt dieses JSON-Format haben
(kein Text außerhalb des JSON!):

{
  "title": "Kurzer prägnanter Titel der Aufgabe",
  "description": "AUSSCHLIESSLICH die Aufgabenstellung im Markdown-Format"
}

STRIKT VERBOTEN in der description:
- Lösungen
- Ergebnisse
- Hinweise
- Wörter wie: Lösung, Hinweis, Ergebnis, Antwort

BEACHTE:
- title: max. 100 Zeichen
- description: nur Aufgabenstellung, gern mehrteilig
- Sprache MUSS ${language} sein
- KEIN zusätzlicher Text außerhalb des JSON
`.trim();

return [
  {
    json: {
      studentPrompt,
      categoryId,
      categoryName,
      topic,
      difficulty,
      language,
      outputFormat,
      systemPrompt,
      userPrompt,
      timestamp: new Date().toISOString()
    }
  }
];

// 1) Rohtext IMMER als String holen
let aiResponseRaw =
  $input.first().json?.message?.content ??
  $input.first().json?.content ??
  $input.first().json?.text ??
  '';

// 2) Absicherung
if (typeof aiResponseRaw !== 'string' || !aiResponseRaw.trim()) {
  throw new Error(
    'Leere oder ungültige AI Response:\n' +
    JSON.stringify($input.first().json, null, 2)
  );
}

// 3) JSON extrahieren (erstes { bis letztes })
const start = aiResponseRaw.indexOf('{');
const end = aiResponseRaw.lastIndexOf('}');
if (start === -1 || end === -1 || end <= start) {
  throw new Error('Kein JSON in AI Response gefunden.\n\nAntwort:\n' + aiResponseRaw);
}
let jsonText = aiResponseRaw.slice(start, end + 1);

// 4) Helper: Control-Chars innerhalb von String-Literalen escapen
function escapeControlCharsInsideStrings(input) {
  let out = '';
  let inString = false;
  let escaped = false;

  for (let i = 0; i < input.length; i++) {
    const ch = input[i];
    const code = ch.charCodeAt(0);

    if (!inString) {
      // außerhalb von Strings ist \n/\t etc als Whitespace ok
      if (ch === '"') inString = true;
      out += ch;
      continue;
    }

    // inString === true
    if (escaped) {
      // aktuelles Zeichen ist escaped, einfach übernehmen
      out += ch;
      escaped = false;
      continue;
    }

    if (ch === '\\') {
      out += ch;
      escaped = true;
      continue;
    }

    if (ch === '"') {
      out += ch;
      inString = false;
      continue;
    }

    // JSON erlaubt KEINE echten Control Characters (0x00-0x1F) innerhalb von Strings
    // => escapen wir sie
    if (code >= 0x00 && code <= 0x1F) {
      switch (ch) {
        case '\n': out += '\\n'; break;
        case '\r': out += '\\r'; break;
        case '\t': out += '\\t'; break;
        case '\b': out += '\\b'; break;
        case '\f': out += '\\f'; break;
        default:
          out += '\\u' + code.toString(16).padStart(4, '0');
      }
      continue;
    }

    out += ch;
  }

  return out;
}

// 5) JSON parsen mit Fallback-Sanitizing
let taskData;
try {
  taskData = JSON.parse(jsonText);
} catch (e1) {
  try {
    const sanitized = escapeControlCharsInsideStrings(jsonText);
    taskData = JSON.parse(sanitized);
  } catch (e2) {
    throw new Error(
      'JSON Parse Error: ' + e2.message +
      '\n\n--- Extracted JSON ---\n' + jsonText +
      '\n\n--- Raw Response ---\n' + aiResponseRaw
    );
  }
}

// 6) Validierung
if (typeof taskData.title !== 'string' || typeof taskData.description !== 'string') {
  throw new Error('JSON enthält kein gültiges title oder description\n\n' + JSON.stringify(taskData, null, 2));
}

// 7) Return
return [{
  json: {
    success: true,
    title: taskData.title.substring(0, 100),
    description: taskData.description,
    timestamp: new Date().toISOString()
  }
}];

// Error Handling
const error = $input.item.json.error || $input.all()[0].json.error;

return [{
  json: {
    success: false,
    error: error?.message || 'Unbekannter Fehler bei der Aufgabengenerierung',
    timestamp: new Date().toISOString()
  }
}];
